const fs = require('fs');
const fsPromises = require('fs').promises;

// Read
fs.readFile('file.txt', 'utf8', (err, data) => {
  if (err) throw err;
  console.log(data);
});

// Async/await
async function read() {
  const data = await fsPromises.readFile('file.txt', 'utf8');
  return data;
}

// Write
fs.writeFileSync('file.txt', 'content');  // sync (blocking)
await fsPromises.writeFile('file.txt', 'content');  // async

// Streams (for large files)
